  const misOrdenes = useMemo(()=>usuario?.rol==="tecnico"?ordenes.filter(o=>o.asignadoA===usuario.id):ordenes,[ordenes,usuario]);
  const ordenesFiltradas = useMemo(()=>misOrdenes
    .filter(o=>phFiltro==="Todos"||o.ph===phFiltro)
    .filter(o=>estadoFiltro==="Todos"||o.estado===estadoFiltro)
    .filter(o=>tipoFiltro==="Todos"||o.tipo===tipoFiltro)
    .filter(o=>tecFiltro==="Todos"||(tecFiltro==="null"?!o.asignadoA:String(o.asignadoA)===tecFiltro))
    .filter(o=>!fechaDesde||o.fecha>=fechaDesde)
    .filter(o=>!fechaHasta||o.fecha<=fechaHasta),
  [misOrdenes,phFiltro,estadoFiltro,tipoFiltro,tecFiltro,fechaDesde,fechaHasta]);
  const misReportes = useMemo(()=>usuario?.rol==="conserje"?reportes.filter(r=>r.ph===usuario.ph):reportes,[reportes,usuario]);
